const http = require('http');

const req = http.request({
  hostname: 'localhost',
  port: 80,
  path: '/health',
  timeout: 300
}, res => {
  process.exit(res.statusCode === 200 ? 0 : 1);
});

req.on('error', () => process.exit(1));
req.on('timeout', () => {
  req.destroy();
  process.exit(1);
});
req.end();

